qry:select.qry:xquery:
for $r in sql('
	SELECT {%=#PARAM:@TABLE %}.{%=#PARAM:@COLRET %} AS VALUE 
	FROM {%=#PARAM:@TABLE %} 
	WHERE {%=#PARAM:@TABLE %}.{%=#PARAM:@COLFND %} = {#PARAM:@COLVAL}
')/ROWS/ROW

for $r in sql('
	SELECT {%=#PARAM:@TABLE %}.{%=#PARAM:@COLRET %} AS VALUE 
	FROM {%=#PARAM:@TABLE %} 
	WHERE {%=#PARAM:@TABLE %}.{%=#PARAM:@COLFNDPRN %} = {#PARAM:@COLVALPRN}
	AND {%=#PARAM:@TABLE %}.{%=#PARAM:@COLFND %} = {#PARAM:@COLVAL}
')/ROWS/ROW

